  "verses": [
    {
      "n": 1,
      "column": "left",
      "text": "Wena Dahwida Dseef.\nma/ preeſch ta augſta\nDseedataja."
    },
    {
      "n": 2,
      "column": "left",
      "text": "Lai tas KUNGS tew pa\nHauſa Behnu Laikâ/ Lai tas\nWahrds ta Deewa Jehkaba tew\npa-augſtina."
    },
    {
      "n": 3,
      "column": "left",
      "text": "Lai wiſch tew Palihdsibu\nfuhta no ſwehtas Weetas/ un\ntew ſpehzina no Zianas."
    },
    {
      "n": 4,
      "column": "left",
      "text": "Lai wiſch peeminin wiſſus\ntawus Uppuuns/ un tawus De-\nDsanto-Uppuuns par Taukajeim\nturr."
    },
    {
      "n": 5,
      "column": "left",
      "text": "Lai wiſch tew pehz tawas\nSirds dohd/ un wiſſas tawas\nPadohmaſchanas peepilda."
    },
    {
      "n": 6,
      "column": "left",
      "text": "Mehs preezajamees pahr\ntawu Pestiſchanu/ un eekſch\nmuhsfa Deewa Wahrda uſzet-\nkam mehs Karrogus/ lai tas\nKUNGS wiſſas tawas Luhg-\nſchanas peepilda."
    },
    {
      "n": 7,
      "column": "left",
      "text": "Nu ſinnu es/ ka tas\nKUNGS ſawam Swaiditam\npalihds/ wiſsch paklausſibs to no\nfawas ſwehtas Debbes/ zaur to\nſtipru Pestiſchann ſawas lab-\nbas Rohkas."
    },
    {
      "n": 8,
      "column": "left",
      "text": "Schee pataujahs us Rat-\nteem/ un ſchee us Sirgeem/ bet\nmehs peeminam ta KUNGA\nmuhfu Deewa Wahrdn."
    },
    {
      "n": 9,
      "column": "left",
      "text": "Tee irr noleekufchees un\nkritutchi/ bet mehs ſtabwam/\nun effam ſtehwn zehluſchees."
    },
    {
      "n": 10,
      "column": "left",
      "text": "At KUNGS palihdsi! wiſſus tawus Eenaidneekus/"
    },
    {
      "n": 1,
      "column": "right",
      "text": "Ta XXI. Dseefma.\nJrr weena Papreeſch/luddinaschona n\nſtus Walſtibas/ kas muhschigi preeſch\nd\nwa buhs un paliks : 2. Bet to\nWalſtiba taps iſpohſita: 9/ 10.\nWena Dahwida D\nma/ preeſch ta au\nDseedataja."
    },
    {
      "n": 2,
      "column": "right",
      "text": "KUNGS/ tas Rehnii\npreezajahs eekſch tawa Spei\nun ka tohti wiſch lihgsmo\npahr tawu Pestiſchanu."
    },
    {
      "n": 3,
      "column": "right",
      "text": "Tu dohd winnam/ ko na Sirds eecribbahs/ un ne leeds/ ko winna Mutte lu Sela."
    },
    {
      "n": 4,
      "column": "right",
      "text": "Jo tu nahz winnam\npreeſchu ar labbu Swehtife\nnu/ tu uſleez us winna Gal\nweenu Krohni no ſchtiſsta Sc"
    },
    {
      "n": 5,
      "column": "right",
      "text": "Wiſch luhs no ten\nOſihwibu/ to eſti tu winn\ndewis/ ilgu Oſihwoſchanu mi\nſchigi muhscham."
    },
    {
      "n": 6,
      "column": "right",
      "text": "Winnam irr leela Get\nba zaur tawu Pestiſchanu/\nleez Gohdibu un Jaakunu\nwinnu."
    },
    {
      "n": 7,
      "column": "right",
      "text": "Jo tu cezell winnu\nSwehtumu muhschigi/ tu eepr\nze winnu ar tawa Wa\nPreeſu."
    },
    {
      "n": 8,
      "column": "right",
      "text": "Jo tas Rehniiſch zerre\nto KUNGII/ un zaur ta Wi"
    },
    {
      "n": 9,
      "column": "right",
      "text": "Tawa Rohka atradd"
    }
  ],
  "confidence": "high",
  "notes": ""
}
